mapper.delete:
DELETE FROM FWK_ORG_CODE
WHERE ORG_ID        = #{orgId}
  AND CODE_GROUP_ID = #{codeGroupId}
  AND CODE          = #{code}
  AND ORG_CODE      = #{orgCode}

mapper.select:
SELECT COUNT(*)
FROM FWK_ORG_CODE
WHERE ORG_ID        = #{orgId}
  AND CODE_GROUP_ID = #{codeGroupId}
  AND CODE          = #{code}
  AND ORG_CODE      = #{orgCode}
